import { useEffect, useRef, useState } from 'react'
import * as THREE from 'three'
import { usePoll } from '@/v2/hooks/usePoll'
import { api } from '@/utils/api'
import { GlobeDrawer } from './GlobeDrawer'
import './Globe.css'

// Exchange locations — keyed by region ID from regions.yaml
const MARKET_GEO = {
  us:               { lat: 40.7128, lng: -74.0060, name: 'NYSE' },
  futures_cme:      { lat: 41.8781, lng: -87.6298, name: 'CME' },
  forex:            { lat: 40.7580, lng: -73.9855, name: 'FOREX' },
  indexes:          { lat: 41.8400, lng: -87.6700, name: 'CBOE' },
  europe_equities:  { lat: 50.1109, lng:   8.6821, name: 'XETRA' },
  europe_lse:       { lat: 51.5074, lng:  -0.1278, name: 'LSE' },
  europe_xetra:     { lat: 50.1155, lng:   8.6842, name: 'FRA' },
  europe_euronext:  { lat: 48.8566, lng:   2.3522, name: 'EURONEXT' },
  europe_six:       { lat: 47.3769, lng:   8.5417, name: 'SIX' },
  asia_tse:         { lat: 35.6762, lng: 139.6503, name: 'TSE' },
  asia_hkex:        { lat: 22.3193, lng: 114.1694, name: 'HKEX' },
  asia_asx:         { lat: -33.8688, lng: 151.2093, name: 'ASX' },
  canada_tsx:       { lat: 43.6532, lng: -79.3832, name: 'TSX' },
  emerging_bse:     { lat: 19.0760, lng:  72.8777, name: 'BSE' },
  emerging_b3:      { lat: -23.5505, lng: -46.6333, name: 'B3' },
  crypto:           { lat: 37.7749, lng: -122.4194, name: 'CRYPTO' },
  us_intraday:      { lat: 40.7060, lng: -74.0088, name: 'IEX' },
}

const COLOR_LIVE = 0x3fb950
const COLOR_INACTIVE = 0xf85149

/* ── Earth texture path (NASA Blue Marble) ───────────────────────────────── */
const EARTH_TEXTURE = '/images/earth-blue-marble.jpg'

function latLngToVec(lat, lng, r) {
  const phi = (90 - lat) * (Math.PI / 180)
  const theta = (lng + 180) * (Math.PI / 180)
  return [
    -(r * Math.sin(phi) * Math.cos(theta)),
    r * Math.cos(phi),
    r * Math.sin(phi) * Math.sin(theta),
  ]
}

/* ── Build Earth globe with real texture ──────────────────────────────────── */

export const Globe = () => {
  const containerRef = useRef(null)
  const globeRef = useRef(null)
  const pinsRef = useRef({})
  const labelsRef = useRef({})
  const cameraRef = useRef(null)
  const rendererRef = useRef(null)
  const [drawerOpen, setDrawerOpen] = useState(false)
  const [hoveredMarket, setHoveredMarket] = useState(null)

  // Poll both endpoints
  const { data: regionsData } = usePoll(() => api('/system/regions'), { intervalMs: 30000 })
  const { data: sourcesData } = usePoll(() => api('/system/sources'), { intervalMs: 15000 })

  // Build markets list from regions
  const markets = Object.entries(regionsData?.regions || {}).map(([id, r]) => ({
    id,
    label: r.label,
    enabled: r.enabled,
    currency: r.currency,
    cached: r.cached_symbols || 0,
    hours: r.market_hours,
  }))

  const liveCount = markets.filter((m) => m.enabled).length

  // Sync pin colors when region data changes
  useEffect(() => {
    const regions = regionsData?.regions || {}
    Object.entries(pinsRef.current).forEach(([id, group]) => {
      const enabled = regions[id]?.enabled
      const hex = enabled ? COLOR_LIVE : COLOR_INACTIVE
      group.children.forEach(child => {
        if (child.material) child.material.color.setHex(hex)
      })
    })
  }, [regionsData])

  // Add/remove pins when region list changes
  useEffect(() => {
    const globe = globeRef.current
    if (!globe || !regionsData) return

    const regions = regionsData.regions || {}
    const existing = pinsRef.current

    // Add pins for new regions
    Object.entries(regions).forEach(([id, r]) => {
      if (existing[id]) return
      const geo = MARKET_GEO[id]
      if (!geo) return

      // Glowing pin with ring effect
      const pinGroup = new THREE.Group()

      // Core dot
      const pin = new THREE.Mesh(
        new THREE.SphereGeometry(0.022, 16, 16),
        new THREE.MeshBasicMaterial({ color: r.enabled ? COLOR_LIVE : COLOR_INACTIVE }),
      )
      pinGroup.add(pin)

      // Outer ring glow
      const ring = new THREE.Mesh(
        new THREE.RingGeometry(0.03, 0.042, 24),
        new THREE.MeshBasicMaterial({
          color: r.enabled ? COLOR_LIVE : COLOR_INACTIVE,
          transparent: true,
          opacity: 0.5,
          side: THREE.DoubleSide,
        }),
      )
      pinGroup.add(ring)

      const [x, y, z] = latLngToVec(geo.lat, geo.lng, 1.02)
      pinGroup.position.set(x, y, z)
      pinGroup.lookAt(0, 0, 0)
      pinGroup.userData = { id, name: geo.name }
      globe.add(pinGroup)
      existing[id] = pinGroup
    })
  }, [regionsData])

  // Three.js scene — runs once
  useEffect(() => {
    if (!containerRef.current) return

    const scene = new THREE.Scene()
    const camera = new THREE.PerspectiveCamera(50, 1, 0.1, 1000)
    camera.position.z = 2.5
    cameraRef.current = camera

    const renderer = new THREE.WebGLRenderer({ alpha: true, antialias: true })
    renderer.setSize(200, 200)
    renderer.setPixelRatio(window.devicePixelRatio)
    containerRef.current.appendChild(renderer.domElement)
    rendererRef.current = renderer

    // Globe mesh — real Earth texture (NASA Blue Marble)
    const textureLoader = new THREE.TextureLoader()
    const earthTexture = textureLoader.load(EARTH_TEXTURE)
    earthTexture.colorSpace = THREE.SRGBColorSpace

    const globe = new THREE.Mesh(
      new THREE.SphereGeometry(1, 64, 64),
      new THREE.MeshPhongMaterial({
        map: earthTexture,
        bumpScale: 0.02,
        shininess: 35,
        emissive: 0x1a3050,
        emissiveIntensity: 0.35,
      }),
    )
    scene.add(globe)
    globeRef.current = globe

    // Inner atmosphere glow — brighter
    scene.add(new THREE.Mesh(
      new THREE.SphereGeometry(1.04, 64, 64),
      new THREE.MeshBasicMaterial({
        color: 0x60d0ff, transparent: true, opacity: 0.15, side: THREE.BackSide,
      }),
    ))

    // Outer atmosphere halo — brighter
    scene.add(new THREE.Mesh(
      new THREE.SphereGeometry(1.12, 64, 64),
      new THREE.MeshBasicMaterial({
        color: 0x58a6ff, transparent: true, opacity: 0.10, side: THREE.BackSide,
      }),
    ))

    // Lighting — bright and inviting
    scene.add(new THREE.AmbientLight(0xffffff, 0.65))
    const dirLight = new THREE.DirectionalLight(0xffffff, 1.0)
    dirLight.position.set(5, 3, 5)
    scene.add(dirLight)

    // Secondary fill light from left
    const fillLight = new THREE.DirectionalLight(0xffffff, 0.35)
    fillLight.position.set(-4, 2, 3)
    scene.add(fillLight)

    // Rim light from behind — brighter cyan accent
    const rimLight = new THREE.DirectionalLight(0x36bdf0, 0.5)
    rimLight.position.set(-3, 1, -5)
    scene.add(rimLight)

    // Very slow rotation: ~120s per revolution → 2π / (120 * 60) ≈ 0.000873
    let animationId
    const animate = () => {
      animationId = requestAnimationFrame(animate)
      globe.rotation.y += 0.000873

      // Pulse all market pins
      const time = Date.now() * 0.001
      const pinEntries = Object.values(pinsRef.current)
      for (let i = 0; i < pinEntries.length; i++) {
        const s = 1 + Math.sin(time * 1.2 + i * 0.7) * 0.12
        pinEntries[i].scale.set(s, s, s)
      }

      renderer.render(scene, camera)
    }
    animate()

    const handleVisibility = () => {
      if (document.hidden) cancelAnimationFrame(animationId)
      else animate()
    }
    document.addEventListener('visibilitychange', handleVisibility)

    const el = containerRef.current
    return () => {
      document.removeEventListener('visibilitychange', handleVisibility)
      cancelAnimationFrame(animationId)
      renderer.dispose()
      el?.removeChild(renderer.domElement)
    }
  }, [])

  // Project 3D positions to 2D for floating labels
  const [labelPositions, setLabelPositions] = useState([])

  useEffect(() => {
    if (!globeRef.current || !cameraRef.current || !rendererRef.current) return

    const updateLabels = () => {
      const globe = globeRef.current
      const camera = cameraRef.current
      const labels = []

      Object.entries(pinsRef.current).forEach(([id, pinGroup]) => {
        const geo = MARKET_GEO[id]
        if (!geo) return

        // Get world position of pin
        const worldPos = new THREE.Vector3()
        pinGroup.getWorldPosition(worldPos)

        // Check if pin is on visible side of globe (facing camera)
        const camDir = new THREE.Vector3().subVectors(camera.position, new THREE.Vector3(0, 0, 0)).normalize()
        const pinDir = worldPos.clone().normalize()
        const dotProduct = camDir.dot(pinDir)

        if (dotProduct > 0.15) {
          // Project to screen coordinates
          const projected = worldPos.clone().project(camera)
          const x = (projected.x * 0.5 + 0.5) * 200
          const y = (-projected.y * 0.5 + 0.5) * 200

          labels.push({
            id,
            name: geo.name,
            x, y,
            enabled: regionsData?.regions?.[id]?.enabled ?? false,
            opacity: Math.min(1, (dotProduct - 0.15) * 3),
          })
        }
      })

      setLabelPositions(labels)
    }

    const interval = setInterval(updateLabels, 500)
    return () => clearInterval(interval)
  }, [regionsData])

  return (
    <>
      <div
        className="globe-wrapper"
        onClick={() => setDrawerOpen((o) => !o)}
        title={`Markets: ${liveCount}/${markets.length} live`}
      >
        <div ref={containerRef} className="globe-container" />

        {/* Floating market labels */}
        <div className="globe-labels">
          {labelPositions.map((lbl) => (
            <div
              key={lbl.id}
              className={`globe-label ${lbl.enabled ? 'live' : 'off'}`}
              style={{
                left: lbl.x,
                top: lbl.y - 18,
                opacity: lbl.opacity * 0.95,
              }}
            >
              {lbl.name}
            </div>
          ))}
        </div>

        {/* Live markets counter badge */}
        <div className="globe-badge">
          <span className="globe-badge-dot" />
          {liveCount}/{markets.length}
        </div>
      </div>

      {drawerOpen && (
        <GlobeDrawer
          markets={markets}
          sources={sourcesData?.sources || []}
          onClose={() => setDrawerOpen(false)}
        />
      )}
    </>
  )
}
