import './GlobeDrawer.css'

export const GlobeDrawer = ({ markets, sources, onClose }) => {
  const liveCount = markets.filter((m) => m.enabled).length

  return (
    <div className="globe-drawer-overlay" onClick={onClose}>
      <div className="globe-drawer" onClick={(e) => e.stopPropagation()}>
        <div className="drawer-header">
          <h3>Global Markets</h3>
          <button className="close-btn" onClick={onClose}>{'\u2715'}</button>
        </div>

        <div className="drawer-content">
          {/* Markets section */}
          <div className="drawer-section-label">Markets</div>
          {markets.length === 0 && (
            <div className="source-item" style={{ justifyContent: 'center', color: 'var(--color-textSecondary)' }}>
              Loading...
            </div>
          )}
          {markets.map((m) => (
            <div key={m.id} className="source-item">
              <div className="source-status">
                <span
                  className="status-icon"
                  style={{ color: m.enabled ? 'var(--color-green)' : 'var(--color-red)' }}
                >
                  {m.enabled ? '\u25CF' : '\u25CB'}
                </span>
                <span className="source-name">{m.label}</span>
              </div>
              <div className="source-metrics">
                <span className="status-label" style={{ color: m.enabled ? 'var(--color-green)' : 'var(--color-red)' }}>
                  {m.enabled ? 'LIVE' : 'OFF'}
                </span>
                <span className="latency">{m.currency}</span>
                {m.cached > 0 && <span className="latency">{m.cached} sym</span>}
              </div>
            </div>
          ))}

          {/* Data sources section */}
          {sources.length > 0 && (
            <>
              <div className="drawer-section-label" style={{ marginTop: 12 }}>Connections</div>
              {sources.map((s) => (
                <div key={s.name} className="source-item">
                  <div className="source-status">
                    <span
                      className="status-icon"
                      style={{ color: s.online ? 'var(--color-green)' : 'var(--color-red)' }}
                    >
                      {s.online ? '\u25CF' : '\u2715'}
                    </span>
                    <span className="source-name">{s.label}</span>
                  </div>
                  <div className="source-metrics">
                    <span className="status-label" style={{ color: s.online ? 'var(--color-green)' : 'var(--color-red)' }}>
                      {s.online ? 'UP' : 'DOWN'}
                    </span>
                    <span className="latency">{s.detail}</span>
                  </div>
                </div>
              ))}
            </>
          )}
        </div>

        <div className="drawer-footer">
          <span className="footer-text" style={{ color: liveCount === markets.length ? 'var(--color-green)' : 'var(--color-amber)' }}>
            {liveCount}/{markets.length} markets live
          </span>
        </div>
      </div>
    </div>
  )
}
